\begin{flushleft}

{\LARGE \bfseries Gravitační a tíhová síla} \\[2mm]
{\color{zfblue}\hrule height 1.5pt}
\vspace{4mm}

\begin{itemize}
    \item \textbf{Gravitační síla} -- síla, kterou se navzájem přitahují všechna tělesa s hmotností.
    \item Čím větší hmotnost, tím větší přitažlivost. Čím větší vzdálenost, tím menší.
    \item Velmi výrazná je u Země (a dalších planet).
\end{itemize}

\vspace{4mm}
{\Large \bfseries \color{zfblue} Gravitační pole Země}
\vspace{2mm}

\begin{center}
\begin{tikzpicture}[scale=1, every node/.style={font=\small}]
    % Země
    \draw[thick, fill=zfblue!20] (0, 0) circle (1.5);
    \node[font=\bfseries] at (0, 0) {Země};

    % Šipky gravitace dovnitř
    \foreach \a in {0, 30, 60, 90, 120, 150, 180, 210, 240, 270, 300, 330} {
        \draw[->, thick, zfred] ({2.5*cos(\a)}, {2.5*sin(\a)}) -- ({1.65*cos(\a)}, {1.65*sin(\a)});
    }
    \node[font=\bfseries, color=zfred] at (3.5, 1.8) {gravitační síla};
    \node[font=\small, color=zfred] at (3.5, 1.4) {míří ke středu};
\end{tikzpicture}
\end{center}

\vspace{4mm}
{\Large \bfseries \color{zfblue} Tíhová síla}
\vspace{2mm}

\begin{itemize}
    \item \textbf{Tíhová síla} ($F_g$) je síla, kterou Země přitahuje těleso.
    \item Působí svisle \textbf{dolů}, do středu Země.
    \item Hmotnost \textbf{nezáleží} na místě, ale tíhová síla se s místem trochu mění.
\end{itemize}

\vspace{2mm}
\noindent
\begin{minipage}[c]{0.5\textwidth}
\begin{tcolorbox}[colback=zfgray, colframe=zfblue!50, boxrule=0.5pt, arc=2pt, left=6pt, right=6pt, top=4pt, bottom=4pt]
\begin{center}
\Large $F_g = m \cdot g$
\end{center}
\end{tcolorbox}
\begin{itemize}
    \item \textbf{$F_g$} -- tíhová síla (N)
    \item \textbf{m} -- hmotnost (kg)
    \item \textbf{g} -- tíhové zrychlení ($\approx 10$ N/kg)
\end{itemize}
\end{minipage}\hfill
\begin{minipage}[c]{0.45\textwidth}
\begin{center}
\begin{tikzpicture}[scale=0.8]
    \draw[thick] (0,0) -- (4,0) -- (2, 3.4) -- cycle;
    \draw[thick] (1.05, 1.7) -- (2.95, 1.7);
    \draw[thick] (2, 0) -- (2, 1.7);
    \node[font=\Large\bfseries, color=zfblue] at (2, 2.4) {$F_g$};
    \node[font=\Large\bfseries, color=zfred] at (1.5, 0.85) {$m$};
    \node[font=\Large\bfseries, color=zfgreen] at (2.5, 0.85) {$g$};
\end{tikzpicture}\\[1mm]
{\scriptsize zakryj veličinu, kterou hledáš}
\end{center}
\end{minipage}

\vspace{2mm}
\noindent
\textbf{Pozn.:} \textbf{g} se nepatrně liší: na rovníku 9,78; na pólech 9,83 N/kg. Pro ZŠ počítáme \textbf{$g = 10$ N/kg} -- snadné počítání.

\vspace{4mm}
{\Large \bfseries \color{zfblue} Příklady tíhové síly}
\vspace{2mm}

\begin{center}
\renewcommand{\arraystretch}{1.3}
\setlength{\tabcolsep}{8pt}
\begin{tabular}{|l|c|c|}
\hline
\rowcolor{zfblue!25}
\bfseries Těleso & \bfseries Hmotnost & \bfseries Tíhová síla \\
\hline
jablko & 0,1 kg & 1 N \\
litr vody & 1 kg & 10 N \\
školní taška & 5 kg & 50 N \\
žák & 40 kg & 400 N \\
auto & 1000 kg & 10\,000 N \\
\hline
\end{tabular}
\end{center}

\vspace{3mm}
{\Large \bfseries \color{zfblue} Tíhová síla na jiných tělesech}
\vspace{2mm}

\begin{center}
\renewcommand{\arraystretch}{1.3}
\setlength{\tabcolsep}{8pt}
\begin{tabular}{|l|c|l|}
\hline
\rowcolor{zfblue!25}
\bfseries Těleso & \bfseries g (N/kg) & \bfseries Co to znamená \\
\hline
Měsíc & 1,6 & vážíš 6$\times$ méně \\
Mars & 3,7 & vážíš asi 3$\times$ méně \\
Země & 10 & běžné \\
Jupiter & 25 & vážíš 2,5$\times$ víc \\
\hline
\end{tabular}
\end{center}

\vspace{3mm}
{\Large \bfseries \color{zfblue} Příklad}
\vspace{2mm}

\noindent
\textbf{Příklad:} Žák má hmotnost 50 kg. Jak velkou tíhovou silou na něj působí Země?

\smallskip
\noindent
\textbf{Zápis:}\\
$m = 50$ kg\\
$g = 10$ N/kg\\
$F_g = ?$ N

\smallskip
\noindent
\textbf{Vzorec:} \quad $F_g = m \cdot g$

\smallskip
\noindent
\textbf{Dosazení:} \quad $F_g = 50~\text{kg} \cdot 10~\text{N/kg} = 500$ N

\smallskip
\noindent
\textbf{Odpověď:} Země přitahuje žáka silou 500 N.

\end{flushleft}
